+        }
+
+        // AltScreen should NOT use cursor save/restore (those are inline-mode specific)
+        let save_count = output
+            .windows(CURSOR_SAVE.len())
+            .filter(|w| *w == CURSOR_SAVE)
+            .count();
+        assert_eq!(save_count, 0, "AltScreen should not save cursor");
+    }
